result = (store_returns.WHERE(
    (store.state == "TN") & (returned_date.year == 2000)
).PARTITION(
    name="store_customer_groups",
    by=(customer_key, store_key)
).CALCULATE(
    customer_total=SUM(store_returns.amount)
).PARTITION(
    name="store_groups", by=store_key
).CALCULATE(
    store_avg=1.2 * AVG(store_customer_groups.customer_total)
).store_customer_groups.WHERE(
    customer_total > store_avg
).store_returns.customer.CALCULATE(
    c_customer_id=_id
).TOP_K(10, by=c_customer_id))
